            surface: surfaceName,
            enabled: surfaceName === "floor"
                ? localLightFloorSegmentTargetingEnabled
                : localLightCeilingSegmentTargetingEnabled,
            segmentCount: getSegments().length,
            maxLightsPerSegment: localLightWallSegmentMaxLightsPerSegment,
