                var b = zones[ids[j]].bounds;
                var gapX = Math.max(0, Math.max(a.minX - b.maxX, b.minX - a.maxX));
                var gapZ = Math.max(0, Math.max(a.minZ - b.maxZ, b.minZ - a.maxZ));
                var edgeDistance = Math.sqrt(gapX * gapX + gapZ * gapZ);
