                if (!applyResult.ok) {
                    notifyGalleryStatus("Nie udalo sie wczytac zapisanego stanu galerii.");
                    galleryStartupFinalizeDebug.stateApplyStatus = "apply-failed";
                    return false;
                }

                if (applyResult.usedFallback) {
                    notifyGalleryStatus("Wczytano stan galerii bez biblioteki autorow. Sprawdz ARTWORK INFO i zapisz ponownie.");
                    galleryStartupFinalizeDebug.stateApplyStatus = "applied-fallback";
                } else {
                    notifyGalleryStatus("Wczytano zapisany stan galerii. Lampy: " + getStateLightCount(result.state) + ".");
                    galleryStartupFinalizeDebug.stateApplyStatus = "applied";
                }

