    function getMobileResponsiveWidth() {
        var values = [];

        if (typeof window !== "undefined" && window.innerWidth) {
            values.push(window.innerWidth);
        }

        if (typeof window !== "undefined" && window.visualViewport && window.visualViewport.width) {
            values.push(window.visualViewport.width);
        }

        if (document.documentElement && document.documentElement.clientWidth) {
            values.push(document.documentElement.clientWidth);
        }

        if (canvas) {
            var canvasRect = canvas.getBoundingClientRect();

            if (canvasRect && canvasRect.width) {
                values.push(canvasRect.width);
            }

            if (canvas.clientWidth) {
                values.push(canvas.clientWidth);
            }
        }

        if (scene && scene.getEngine && scene.getEngine()) {
            var renderWidth = scene.getEngine().getRenderWidth();

            if (renderWidth) {
                values.push(renderWidth);
            }
        }

        if (!values.length) {
            return window.innerWidth || 9999;
        }

        return Math.min.apply(null, values);
    }

    function getMobileViewportShortSide() {
        var width = window.visualViewport && window.visualViewport.width
            ? window.visualViewport.width
            : window.innerWidth;
        var height = window.visualViewport && window.visualViewport.height
            ? window.visualViewport.height
            : window.innerHeight;

        return Math.min(width || 9999, height || 9999);
    }

    function shouldUseMobileViewerMode() {
        return !!(
            galleryDeviceProfile.useMobileViewerControls &&
            (
                getMobileResponsiveWidth() <= mobileViewerBreakpoint ||
                getMobileViewportShortSide() <= 600
            )
        );
    }

    function refreshMobileViewerMode() {
        var shouldEnable = shouldUseMobileViewerMode();
        var mobileHud = document.getElementById("galleryMobileHud");

        if (document.body) {
            document.body.classList.toggle("gallery-mobile-viewer-enabled", shouldEnable);
        }

        if (mobileHud) {
            mobileHud.setAttribute("data-mobile-viewer", shouldEnable ? "enabled" : "disabled");
        }

        if (shouldEnable === mobileViewerEnabled) {
            // Stage 12C66C1: heal any generic camera reattach that may have happened
            // after Inspect, recovery or a viewport refresh. Mobile Viewer must never
            // keep Babylon touch controls attached in parallel with custom input.
            if (shouldEnable && !editMode) {
                try { camera.detachControl(canvas); } catch (mobileRefreshDetachError) {}
                disableGalleryBuiltInKeyboardCameraMovement();
                clearGalleryBuiltInCameraMotionResidue();
            }
            setMobileViewerUiVisible(isMobileViewerActive());
            return;
        }

        mobileViewerEnabled = shouldEnable;

        if (mobileViewerEnabled) {
            canvas.style.touchAction = "none";

            if (!editMode) {
                camera.detachControl(canvas);
                setMobileViewerUiVisible(true);
            } else {
                setMobileViewerUiVisible(false);
            }

            if (!mobileStartCameraApplied && assetsLoaded >= assetsToLoad) {
                setMobileStartCameraPosition();
            }
        } else {
            resetMobileJoystick();

            mobileLookActive = false;
            mobileLookPointerId = null;

            setMobileViewerUiVisible(false);
            canvas.style.touchAction = "";

            if (!editMode) {
                attachGalleryCameraControl();
            }
        }
    }

    function isMobileViewerActive() {
        return mobileViewerEnabled && !editMode;
    }

    function setMobileViewerUiVisible(isVisible) {
        if (!mobileViewerControls) {
            return;
        }

        mobileViewerControls.style.display = isVisible ? "block" : "none";
    }


    function resetMobileJoystick() {
        mobileJoystickActive = false;
        mobileJoystickPointerId = null;
        mobileJoystickVector.x = 0;
        mobileJoystickVector.y = 0;

        if (mobileJoystickKnob) {
            mobileJoystickKnob.style.transform = "translate(-50%, -50%)";
        }
    }

    function updateMobileFloorBounds() {
        if (!floorMeshes || floorMeshes.length === 0) {
            mobileFloorBounds = null;
            return;
        }

        var minX = Infinity;
        var maxX = -Infinity;
        var minZ = Infinity;
        var maxZ = -Infinity;

        floorMeshes.forEach(function (mesh) {
            mesh.computeWorldMatrix(true);

            var boundingInfo = mesh.getBoundingInfo();
            var minimum = boundingInfo.boundingBox.minimumWorld;
            var maximum = boundingInfo.boundingBox.maximumWorld;

            minX = Math.min(minX, minimum.x);
            maxX = Math.max(maxX, maximum.x);
            minZ = Math.min(minZ, minimum.z);
            maxZ = Math.max(maxZ, maximum.z);
        });

        if (
            isFinite(minX) &&
            isFinite(maxX) &&
            isFinite(minZ) &&
            isFinite(maxZ)
        ) {
            mobileFloorBounds = {
                minX: minX,
                maxX: maxX,
                minZ: minZ,
                maxZ: maxZ
            };
        }
    }

    function isMobileCameraPositionOnFloor(candidatePosition) {
        if (!floorMeshes || floorMeshes.length === 0) {
            return true;
        }

        if (mobileFloorBounds) {
            var margin = 0.22;

            if (
                candidatePosition.x < mobileFloorBounds.minX + margin ||
                candidatePosition.x > mobileFloorBounds.maxX - margin ||
                candidatePosition.z < mobileFloorBounds.minZ + margin ||
                candidatePosition.z > mobileFloorBounds.maxZ - margin
            ) {
                return false;
            }
        }

        var rayOrigin = new BABYLON.Vector3(
            candidatePosition.x,
            candidatePosition.y + 4,
            candidatePosition.z
        );

        var ray = new BABYLON.Ray(
            rayOrigin,
            new BABYLON.Vector3(0, -1, 0),
            mobileFloorRayLength
        );

        var hit = scene.pickWithRay(
            ray,
            function (mesh) {
                return floorMeshes.includes(mesh);
            }
        );

        return !!(hit && hit.hit);
    }

    function setMobileStartCameraPosition() {
        // Mobile nie ma osobnej pozycji startowej.
        // Zapamietuje aktualna pozycje i rotacje kamery, czyli te same ustawienia,
        // ktore dostaje wersja desktopowa.
        mobileInitialCameraPosition = camera.position.clone();
        mobileInitialCameraRotation = camera.rotation.clone();
        mobileStartCameraApplied = true;
    }


    function updateMobileJoystickFromPointer(event) {
        if (!mobileJoystickBase || !mobileJoystickKnob) {
            return;
        }

        var rect = mobileJoystickBase.getBoundingClientRect();
        var centerX = rect.left + rect.width / 2;
        var centerY = rect.top + rect.height / 2;
        var maxDistance = rect.width * 0.34;

        var dx = event.clientX - centerX;
        var dy = event.clientY - centerY;

        var distance = Math.sqrt(dx * dx + dy * dy);

        if (distance > maxDistance && distance > 0) {
            dx = dx / distance * maxDistance;
            dy = dy / distance * maxDistance;
        }

        mobileJoystickVector.x = dx / maxDistance;
        mobileJoystickVector.y = dy / maxDistance;

        mobileJoystickKnob.style.transform =
            "translate(calc(-50% + " + dx + "px), calc(-50% + " + dy + "px))";
    }



    // STAGE 12C1 - VIEWER WASD / MOBILE JOYSTICK GROUNDED WALK
    function viewerMovementExpBlend(rate, dt) {
        return 1 - Math.exp(-Math.max(0.001, rate) * dt);
    }

    function viewerMovementClamp01(value) {
        return Math.max(0, Math.min(1, value));
    }

    function viewerMovementSmoothstep(value) {
        value = viewerMovementClamp01(value);
        return value * value * (3 - 2 * value);
    }

    function clearViewerWASDMoveKeys() {
        viewerMoveKeys.w = false;
        viewerMoveKeys.a = false;
        viewerMoveKeys.s = false;
        viewerMoveKeys.d = false;
        viewerMoveKeys.shift = false;
    }

    function clearViewerWASDVisualOffsets() {
        if (!camera) {
            return;
        }

        if (viewerMovementVisualOffset.lengthSquared() > 0.0000001) {
            camera.position.subtractInPlace(viewerMovementVisualOffset);
            viewerMovementVisualOffset.set(0, 0, 0);
        }

        if (Math.abs(viewerMovementVisualPitchOffset) > 0.0000001) {
            camera.rotation.x -= viewerMovementVisualPitchOffset;
            viewerMovementVisualPitchOffset = 0;
        }

        if (Math.abs(viewerMovementVisualRollOffset) > 0.0000001) {
            camera.rotation.z -= viewerMovementVisualRollOffset;
            viewerMovementVisualRollOffset = 0;
        }

        // STAGE 12C2:
        // Viewer ma trzymać horyzont. Poprzedni visual roll potrafił zostawić kadr pod skosem,
        // a start chodzenia prostował kamerę skokiem.
        if (
            viewerCameraRollLockEnabled &&
            !editMode &&
            Math.abs(camera.rotation.z) > 0.000001
        ) {
            camera.rotation.z = 0;
        }
    }

    function resetViewerWASDMovementRuntime(clearKeys) {
        clearViewerWASDVisualOffsets();

        viewerMovementVelocity.set(0, 0, 0);
        viewerMovementCurrentSpeed01 = 0;
        viewerMovementTargetSpeed01 = 0;
        viewerMovementStepTimer = 0;
        viewerMovementLastHadInput = false;
        viewerMovementStopSettleTimer = 999;
        viewerMovementStopBounceSpeed01 = 0;
        viewerMovementWasManualInputActive = false;

        if (clearKeys) {
            clearViewerWASDMoveKeys();
        }
    }

    function isViewerWASDMovementActive() {
        return !!(
            viewerWASDMovementEnabled &&
            !editMode &&
            viewerIntroOverlayMovementUnlocked &&
            !isDraggingArtwork &&
            !isDraggingSphere
        );
    }

    function getViewerMovementForwardFlat() {
        var forward = camera.getDirection(new BABYLON.Vector3(0, 0, 1));
        forward.y = 0;

        if (forward.lengthSquared() > 0.00001) {
            forward.normalize();
        }

        return forward;
    }

    function getViewerMovementRightFlat() {
        var right = camera.getDirection(new BABYLON.Vector3(1, 0, 0));
        right.y = 0;

        if (right.lengthSquared() > 0.00001) {
            right.normalize();
        }

        return right;
    }

    function getViewerWASDInputState() {
        var x = 0;
        var z = 0;
        var analog = false;

        if (isMobileViewerActive() && (mobileJoystickActive || mobileCanvasMoveActive)) {
            var activeMobileVector = mobileJoystickActive ? mobileJoystickVector : mobileCanvasMoveVector;
            var deadZone = viewerMovementConfig.joystickDeadZone || 0.08;
            var joystickZ = Math.abs(activeMobileVector.y) >= deadZone ? -activeMobileVector.y : 0;

            // STAGE 12C3:
            // Mobile joystick X wraca do obrotu kamery.
            // Nie dodajemy go do x/strafe, bo to psuło poprzedni feeling mobile.
            x += 0;
            z += joystickZ;
            analog = true;
        } else {
            if (viewerMoveKeys.d) {
                x += 1;
            }

            if (viewerMoveKeys.a) {
                x -= 1;
            }

            if (viewerMoveKeys.w || galleryDesktopDpadState.forward) {
                z += 1;
            }

            if (viewerMoveKeys.s || galleryDesktopDpadState.backward) {
                z -= 1;
            }
        }

        var magnitude = Math.sqrt(x * x + z * z);

        if (magnitude > 1) {
            x /= magnitude;
            z /= magnitude;
            magnitude = 1;
        }

        if (magnitude <= 0.0001) {
            return {
                hasInput: false,
                analog: analog,
                magnitude: 0,
                direction: BABYLON.Vector3.Zero(),
                rawX: 0,
                rawZ: 0
            };
        }

        var forward = getViewerMovementForwardFlat();
        var right = getViewerMovementRightFlat();
        var direction = forward.scale(z).add(right.scale(x));
        direction.y = 0;

        if (direction.lengthSquared() > 0.00001) {
            direction.normalize();
        }

        return {
            hasInput: true,
            analog: analog,
            magnitude: magnitude,
            direction: direction,
            rawX: x,
            rawZ: z
        };
    }

    function updateViewerMovementSpeedFactor(inputState, dt) {
        var hasInput = inputState && inputState.hasInput;
        var target = hasInput ? inputState.magnitude : 0;
        viewerMovementTargetSpeed01 = target;

        var rate = hasInput
            ? 1 / Math.max(0.001, viewerMovementConfig.inputRampTime || 0.105)
            : viewerMovementConfig.braking || 35.0;

        viewerMovementCurrentSpeed01 +=
            (viewerMovementTargetSpeed01 - viewerMovementCurrentSpeed01) *
            viewerMovementExpBlend(rate, dt);

        viewerMovementCurrentSpeed01 = viewerMovementClamp01(viewerMovementCurrentSpeed01);

        if (
            hasInput &&
            !inputState.analog &&
            inputState.magnitude > 0.95
        ) {
            viewerMovementCurrentSpeed01 = Math.max(
                viewerMovementCurrentSpeed01,
                viewerMovementConfig.inputStartStrength || 0.91
            );
        }

        return viewerMovementSmoothstep(viewerMovementCurrentSpeed01);
    }

    function updateViewerMovementStopSettle(dt, hasInput, speedBeforeStop) {
        if (viewerMovementLastHadInput && !hasInput) {
            viewerMovementStopSettleTimer = 0;
            viewerMovementStopBounceSpeed01 = Math.min(
                1,
                speedBeforeStop / Math.max(0.001, viewerMovementConfig.speed || 3.58)
            );

            if (viewerMovementLastMoveDirection.lengthSquared() > 0.00001) {
                viewerMovementStopBounceDirection.copyFrom(viewerMovementLastMoveDirection);
                viewerMovementStopBounceDirection.normalize();
            }
        }

        viewerMovementLastHadInput = hasInput;

        var settleDuration = viewerMovementConfig.stopSettleDuration || 0.10;
        var bounceDuration = viewerMovementConfig.stopBounceDuration || 0.23;
        var duration = Math.max(settleDuration, bounceDuration);

        if (viewerMovementStopSettleTimer > duration) {
            return {
                pitch: 0,
                positionOffset: BABYLON.Vector3.Zero()
            };
        }

        viewerMovementStopSettleTimer += dt;

        var settlePitch = 0;

        if (settleDuration > 0 && viewerMovementStopSettleTimer <= settleDuration) {
            var tSettle = viewerMovementClamp01(viewerMovementStopSettleTimer / settleDuration);
            var settleWave = Math.sin(tSettle * Math.PI);
            var settleDecay = Math.pow(1 - tSettle, 1.4);

            settlePitch = -settleWave * settleDecay * (viewerMovementConfig.stopSettlePitch || 0.0009);
        }

        var bouncePitch = 0;
        var bounceOffset = BABYLON.Vector3.Zero();

        if (bounceDuration > 0 && viewerMovementStopSettleTimer <= bounceDuration) {
            var tBounce = viewerMovementClamp01(viewerMovementStopSettleTimer / bounceDuration);
            var frequency = viewerMovementConfig.stopBounceFrequency || 0.66;
            var wave = Math.sin(tBounce * Math.PI * 2 * frequency);
            var decay = Math.pow(1 - tBounce, 2.15);
            var amount = wave * decay * (0.45 + viewerMovementStopBounceSpeed01 * 0.55);

            bounceOffset = viewerMovementStopBounceDirection.scale(
                amount * (viewerMovementConfig.stopBounceDistance || 0.032)
            );
            bouncePitch = -amount * (viewerMovementConfig.stopBouncePitch || 0.0044);
        }

        return {
            pitch: settlePitch + bouncePitch,
            positionOffset: bounceOffset
        };
    }

    function getViewerMovementStepVisual(dt, hasInput, speedMagnitude) {
        var speed01 = Math.min(1, speedMagnitude / Math.max(0.001, viewerMovementConfig.speed || 3.58));

        if (hasInput && speed01 > 0.04) {
            viewerMovementStepTimer += dt *
                (viewerMovementConfig.stepFrequency || 1.12) *
                (0.75 + speed01 * 0.35);
        } else {
            viewerMovementStepTimer += dt * 0.4;
        }

        var phase = viewerMovementStepTimer * Math.PI * 2;
        var up = Math.abs(Math.sin(phase));
        var compression = Math.pow(Math.max(0, Math.sin(phase + Math.PI * 0.35)), 2);

        var height =
            up * (viewerMovementConfig.bobHeight || 0.0078) * speed01 -
            compression * (viewerMovementConfig.compression || 0.0054) * speed01;

        var pitch =
            Math.sin(phase + Math.PI * 0.2) *
            (viewerMovementConfig.pitchAmount || 0.0017) *
            speed01;

        var roll =
            Math.sin(phase * 0.5) *
            (viewerMovementConfig.rollAmount || 0.0016) *
            speed01;

        return {
            height: height,
            pitch: pitch,
            roll: roll
        };
    }

    function applyViewerMovementVisualOffsets(offset, pitch, roll) {
        clearViewerWASDVisualOffsets();

        viewerMovementVisualOffset.copyFrom(offset || BABYLON.Vector3.Zero());
        viewerMovementVisualPitchOffset = pitch || 0;
        viewerMovementVisualRollOffset = roll || 0;

        if (viewerMovementVisualOffset.lengthSquared() > 0.0000001) {
            camera.position.addInPlace(viewerMovementVisualOffset);
        }

        if (Math.abs(viewerMovementVisualPitchOffset) > 0.0000001) {
            camera.rotation.x += viewerMovementVisualPitchOffset;
        }

        if (Math.abs(viewerMovementVisualRollOffset) > 0.0000001) {
            camera.rotation.z += viewerMovementVisualRollOffset;
        }
    }

    function moveViewerCameraWithGroundedCollision(deltaVector) {
        if (!deltaVector || deltaVector.lengthSquared() <= 0.0000001) {
            return false;
        }

        var beforeMove = camera.position.clone();
        var candidatePosition = camera.position.add(deltaVector);

        // STAGE 12C10:
        // Viewer WASD/joystick can move only over the actual floor.
        // This is no longer mobile-only, because desktop WASD could leave the map.
        if (!editMode && !isMobileCameraPositionOnFloor(candidatePosition)) {
            viewerMovementVelocity.set(0, 0, 0);
            return false;
        }

        moveCameraWithViewerCollisionIfActive(deltaVector);

        if (!editMode && !isMobileCameraPositionOnFloor(camera.position)) {
            camera.position.copyFrom(beforeMove);
            viewerMovementVelocity.set(0, 0, 0);
            return false;
        }

        return true;
    }

    function updateViewerMobileJoystickTurn(dt) {
        if (
            !viewerMovementMobileJoystickTurnEnabled ||
            !isMobileViewerActive() ||
            !(mobileJoystickActive || mobileCanvasMoveActive) ||
            editMode ||
            !camera
        ) {
            return false;
        }

        var activeMobileVector = mobileJoystickActive ? mobileJoystickVector : mobileCanvasMoveVector;
        var turnInput = activeMobileVector.x || 0;

        if (Math.abs(turnInput) < viewerMovementMobileJoystickTurnDeadZone) {
            return false;
        }

        // STAGE 12C3:
        // Stary mobile feeling: joystick w lewo/prawo obraca kamerę.
        // Nie ma bocznego dryfu i nie ma A/D strafe na mobile.
        clearViewerWASDVisualOffsets();
        scene.stopAnimation(camera);
        camera.rotation.y += turnInput * viewerMovementMobileJoystickTurnSpeed * dt;
        camera.rotation.z = 0;

        return true;
    }

// STAGE 12C64R — SMOOTH INSPECT PLAYBACK / INTERACTION READINESS GATE
    // Playback is fully prevalidated; viewer control unlocks only after heavy startup work and stable warm-up frames.

    // STAGE 12C64Q — INSPECT OWNS CAMERA TRANSITION / CLEAN WASD HANDOFF
    // One owner at a time:
    // WALK       -> normal Viewer/Edit movement owns the camera.
    // TRANSITION -> only the Inspect transition controller owns the camera.
    // INSPECT    -> camera rests at the exact focus transform until manual input returns to WALK.
    var galleryInspectCameraRuntime = {
        state: "WALK",
        transitionId: 0,
        reason: "initial",
        controlsDetached: false,
        startedAt: 0,
        completedAt: 0
    };

    function isGalleryInspectCameraTransitionActive() {
        return galleryInspectCameraRuntime.state === "TRANSITION";
    }

    function isGalleryInspectCameraOwnedByInspect() {
        return galleryInspectCameraRuntime.state === "TRANSITION" || galleryInspectCameraRuntime.state === "INSPECT";
    }

    function syncGalleryInspectCameraCollisionHandoff() {
        if (!camera || !camera.position) return;
        viewerWallLastSafeCameraPosition = camera.position.clone();
        viewerWallCollisionLastObservedPosition = camera.position.clone();
    }

    function detachGalleryCameraForInspectTransition() {
        if (galleryInspectCameraRuntime.controlsDetached || !camera || !canvas) return;
        try {
            camera.detachControl(canvas);
            galleryInspectCameraRuntime.controlsDetached = true;
        } catch (error) {}
    }

    function restoreGalleryCameraAfterInspectTransition() {
        if (!galleryInspectCameraRuntime.controlsDetached) return;
        galleryInspectCameraRuntime.controlsDetached = false;
        try {
            attachGalleryCameraControl();
        } catch (error) {}
    }

    function beginGalleryInspectCameraTransition(reason) {
        markGalleryViewerActivity(reason || "inspect-transition");
        stopViewerSafeFocusRuntimeAnimation();
        try { scene.stopAnimation(camera); } catch (error) {}
        try { endDesktopViewerMiddleLook(null); } catch (error) {}
        try { endMobileCanvasLook(null); } catch (error) {}
        resetViewerWASDMovementRuntime(true);
        if (typeof clearEditMoveKeys === "function") clearEditMoveKeys();
        detachGalleryCameraForInspectTransition();
        galleryInspectCameraRuntime.state = "TRANSITION";
        galleryInspectCameraRuntime.transitionId += 1;
        galleryInspectCameraRuntime.reason = reason || "inspect-transition";
        galleryInspectCameraRuntime.startedAt = Date.now();
        return galleryInspectCameraRuntime.transitionId;
    }

    function completeGalleryInspectCameraTransition() {
        galleryInspectCameraRuntime.state = "INSPECT";
        galleryInspectCameraRuntime.completedAt = Date.now();
        syncGalleryInspectCameraCollisionHandoff();
        restoreGalleryCameraAfterInspectTransition();
    }

    function releaseGalleryInspectCameraToWalk(reason) {
        stopViewerSafeFocusRuntimeAnimation();
        galleryInspectCameraRuntime.state = "WALK";
        galleryInspectCameraRuntime.reason = reason || "walk";
        syncGalleryInspectCameraCollisionHandoff();
        restoreGalleryCameraAfterInspectTransition();
    }

    function hasViewerTransitionCancelInput() {
        var keyboard = !!(viewerMoveKeys.w || viewerMoveKeys.a || viewerMoveKeys.s || viewerMoveKeys.d);
        var joystick = !!(
            isMobileViewerActive() &&
            (mobileJoystickActive || mobileCanvasMoveActive) &&
            (Math.abs((mobileJoystickActive ? mobileJoystickVector : mobileCanvasMoveVector).x || 0) >= (viewerMovementMobileJoystickTurnDeadZone || 0.08) ||
             Math.abs((mobileJoystickActive ? mobileJoystickVector : mobileCanvasMoveVector).y || 0) >= (viewerMovementConfig.joystickDeadZone || 0.08))
        );
        return keyboard || joystick;
    }


    function updateGalleryDesktopDpadTurn(dt) {
        if (!isGalleryDesktopPointerNavigationAvailable() || !camera) {
            return false;
        }

        var turnInput = (galleryDesktopDpadState.turnRight ? 1 : 0) - (galleryDesktopDpadState.turnLeft ? 1 : 0);

        if (!turnInput) {
            return false;
        }

        if (typeof isViewerIntroOverlayBlockingMovement === "function" && isViewerIntroOverlayBlockingMovement()) {
            resetGalleryDesktopDpadState();
            return false;
        }

        if (galleryInspectRuntime && galleryInspectRuntime.active) {
            closeGalleryInspect("desktop-dpad-movement");
        }

        clearViewerWASDVisualOffsets();
        try {
            scene.stopAnimation(camera);
        } catch (error) {}
        camera.rotation.y += turnInput * galleryDesktopDpadTurnSpeed * Math.max(0.001, dt || 0.016);
        camera.rotation.z = 0;
        markGalleryViewerActivity("desktop-dpad-turn");
        return true;
    }

    function shouldEnforceMobileViewerGroundedWalkHeight() {
        if (!isMobileViewerActive() || editMode || !camera || !camera.position) {
            return false;
        }

        if (typeof isGalleryInspectCameraOwnedByInspect === "function" && isGalleryInspectCameraOwnedByInspect()) {
            return false;
        }

        if (typeof galleryFocusPreviewRuntime !== "undefined" && galleryFocusPreviewRuntime && galleryFocusPreviewRuntime.active) {
            return false;
        }

        return true;
    }

    function enforceMobileViewerGroundedWalkHeight() {
        if (!shouldEnforceMobileViewerGroundedWalkHeight()) {
            return false;
        }

        var walkY = getGalleryDefaultWalkCameraY();
        if (isFinite(Number(walkY)) && Math.abs(camera.position.y - Number(walkY)) > 0.0001) {
            camera.position.y = Number(walkY);
        }

        if (camera.rotation) {
            camera.rotation.z = 0;
        }

        clearGalleryBuiltInCameraMotionResidue();
        return true;
    }

    function resetGalleryMobileNavigationState(reason) {
        resetMobileJoystick();
        if (mobileLookActive) {
            endMobileCanvasLook(null, true);
        } else {
            mobileLookPointerId = null;
            resetMobileCanvasMoveGesture();
        }
        clearViewerWASDMoveKeys();
        resetGalleryDesktopDpadState();
        viewerMovementVelocity.set(0, 0, 0);
        clearGalleryBuiltInCameraMotionResidue();
        enforceMobileViewerGroundedWalkHeight();
        return reason || "mobile-input-reset";
    }

    function updateViewerWASDMovement() {
        if (isGalleryInspectCameraTransitionActive()) {
            if (!hasViewerTransitionCancelInput()) return;
            closeGalleryInspect("viewer-manual-movement");
        }

        clearViewerWASDVisualOffsets();
        enforceMobileViewerGroundedWalkHeight();

        var dt = scene.getEngine().getDeltaTime() / 1000;
        dt = Math.min(0.05, Math.max(0.001, dt));

        if (!isViewerWASDMovementActive()) {
            resetViewerWASDMovementRuntime(false);
            return;
        }

        var mobileJoystickTurnActive = updateViewerMobileJoystickTurn(dt);
        var desktopDpadTurnActive = updateGalleryDesktopDpadTurn(dt);

        var inputState = getViewerWASDInputState();
        var hasInput = inputState.hasInput;
        if (hasInput || mobileJoystickTurnActive || desktopDpadTurnActive || viewerMovementVelocity.length() > 0.035) {
            markGalleryViewerActivity("viewer-movement");
        }
        if ((hasInput || mobileJoystickTurnActive || desktopDpadTurnActive) && galleryInspectRuntime.active) {
            closeGalleryInspect("viewer-manual-movement");
        }
        updateGalleryFocusPreviewReturnToWalk(dt, hasInput || mobileJoystickTurnActive || desktopDpadTurnActive);
        var speedBeforeStop = viewerMovementVelocity.length();

        if (hasInput && inputState.direction.lengthSquared() > 0.00001) {
            viewerMovementLastMoveDirection.copyFrom(inputState.direction);
            viewerMovementLastMoveDirection.normalize();
        }

        if ((hasInput || mobileJoystickTurnActive || desktopDpadTurnActive) && !viewerMovementWasManualInputActive) {
            scene.stopAnimation(camera);

            if (typeof stopViewerSafeFocusRuntimeAnimation === "function") {
                stopViewerSafeFocusRuntimeAnimation();
            }
        }

        viewerMovementWasManualInputActive = hasInput || mobileJoystickTurnActive || desktopDpadTurnActive;

        var speedFactor = updateViewerMovementSpeedFactor(inputState, dt);
        var speed = viewerMovementConfig.speed || 3.58;

        if (viewerMoveKeys.shift && !isMobileViewerActive()) {
            speed *= viewerMovementConfig.sprintMultiplier || 1.22;
        }

        var desiredVelocity = hasInput
            ? inputState.direction.scale(speed * speedFactor)
            : BABYLON.Vector3.Zero();

        var blend = viewerMovementExpBlend(
            hasInput ? viewerMovementConfig.acceleration : viewerMovementConfig.braking,
            dt
        );

        viewerMovementVelocity.x += (desiredVelocity.x - viewerMovementVelocity.x) * blend;
        viewerMovementVelocity.z += (desiredVelocity.z - viewerMovementVelocity.z) * blend;

        if (
            !hasInput ||
            Math.abs(inputState.rawX) < 0.001 ||
            isMobileViewerActive()
        ) {
            var right = getViewerMovementRightFlat();
            var lateral = BABYLON.Vector3.Dot(viewerMovementVelocity, right);
            var sideBlend = viewerMovementExpBlend(viewerMovementConfig.sideFriction || 43.0, dt);
            viewerMovementVelocity.subtractInPlace(right.scale(lateral * sideBlend));
        }

        if (!hasInput && viewerMovementVelocity.length() < (viewerMovementConfig.snapStopSpeed || 0.037)) {
            viewerMovementVelocity.set(0, 0, 0);
        }

        var movementDelta = viewerMovementVelocity.scale(dt);
        moveViewerCameraWithGroundedCollision(movementDelta);
        enforceMobileViewerGroundedWalkHeight();

        var step = getViewerMovementStepVisual(dt, hasInput, viewerMovementVelocity.length());
        var stopSettle = updateViewerMovementStopSettle(dt, hasInput, speedBeforeStop);

        var visualOffset = new BABYLON.Vector3(
            stopSettle.positionOffset.x,
            step.height,
            stopSettle.positionOffset.z
        );

        applyViewerMovementVisualOffsets(
            visualOffset,
            step.pitch + stopSettle.pitch,
            0
        );
    }


    function isGalleryTouchGestureUiTarget(target) {
        return !!(
            target &&
            target.closest &&
            target.closest(
                "#mobileViewerControls, #galleryArtworkInfoPopup, #berryboyViewerIntroOverlay, " +
                "#galleryEditorPanel, #siteHeader, #galleryBootGuard, button, a, input, textarea, select, label"
            )
        );
    }

    function clearMobileCanvasHoldTimer() {
        if (mobileCanvasHoldTimer) {
            clearTimeout(mobileCanvasHoldTimer);
            mobileCanvasHoldTimer = null;
        }
    }

    function resetMobileCanvasMoveGesture() {
        clearMobileCanvasHoldTimer();
        mobileCanvasMoveActive = false;
        mobileCanvasMoveVector.x = 0;
        mobileCanvasMoveVector.y = 0;
        mobileCanvasGestureMode = "idle";
    }

    function updateMobileCanvasMoveVector(event) {
        var dx = event.clientX - mobileLookStartX;
        var dy = event.clientY - mobileLookStartY;
        var radius = Math.max(24, mobileCanvasMoveRadius);
        var length = Math.sqrt(dx * dx + dy * dy);

        if (length > radius) {
            dx = dx / length * radius;
            dy = dy / length * radius;
        }

        mobileCanvasMoveVector.x = BABYLON.Scalar.Clamp(dx / radius, -1, 1);
        mobileCanvasMoveVector.y = BABYLON.Scalar.Clamp(dy / radius, -1, 1);
    }

    function beginMobileCanvasLook(event) {
        if (!isMobileViewerActive() || !event || isGalleryTouchGestureUiTarget(event.target)) {
            return false;
        }

        if (typeof isViewerIntroOverlayBlockingMovement === "function" && isViewerIntroOverlayBlockingMovement()) {
            return false;
        }

        // One canvas gesture has one owner. A second finger must not replace the
        // captured pointer and leave the first movement vector active.
        if (mobileLookActive) {
            if (event.cancelable) event.preventDefault();
            return false;
        }

        resetMobileCanvasMoveGesture();
        mobileLookActive = true;
        mobileLookPointerId = event.pointerId;
        mobileLookStartX = event.clientX;
        mobileLookStartY = event.clientY;
        mobileLookLastX = event.clientX;
        mobileLookLastY = event.clientY;
        mobileLookMoved = false;
        // While the real joystick is held, the second thumb is camera-look only.
        // The temporary hold joystick is allowed only when no other movement owner exists.
        mobileCanvasGestureMode = mobileJoystickActive ? "look" : "pending";

        if (canvas && canvas.setPointerCapture && event.pointerId !== undefined) {
            try {
                canvas.setPointerCapture(event.pointerId);
            } catch (error) {}
        }

        if (mobileCanvasGestureMode === "pending") {
            mobileCanvasHoldTimer = setTimeout(function () {
                mobileCanvasHoldTimer = null;

                if (!mobileLookActive || mobileCanvasGestureMode !== "pending") {
                    return;
                }

                if (mobileJoystickActive) {
                    mobileCanvasGestureMode = "look";
                    mobileLookMoved = true;
                    return;
                }

                mobileCanvasGestureMode = "move";
                mobileCanvasMoveActive = true;
                mobileLookMoved = true;
                markGalleryViewerActivity("mobile-hold-movement-ready");
            }, mobileCanvasHoldDelayMs);
        }

        if (event.cancelable) {
            event.preventDefault();
        }
        return true;
    }

    function updateMobileCanvasLook(event) {
        if (!mobileLookActive || !event) {
            return false;
        }

        if (mobileLookPointerId !== null && event.pointerId !== mobileLookPointerId) {
            return false;
        }

        if (event.cancelable) {
            event.preventDefault();
        }

        var totalDx = event.clientX - mobileLookStartX;
        var totalDy = event.clientY - mobileLookStartY;
        var crossedThreshold = Math.abs(totalDx) > mobileTapMoveThreshold || Math.abs(totalDy) > mobileTapMoveThreshold;

        if (mobileCanvasGestureMode === "pending" && crossedThreshold) {
            clearMobileCanvasHoldTimer();
            mobileCanvasGestureMode = "look";
            mobileLookMoved = true;
        }

        if (mobileCanvasGestureMode === "move") {
            updateMobileCanvasMoveVector(event);
            if (galleryInspectRuntime.active) {
                closeGalleryInspect("mobile-hold-movement");
            }
            markGalleryViewerActivity("mobile-hold-movement");
            return true;
        }

        if (mobileCanvasGestureMode !== "look") {
            return true;
        }

        var dx = event.clientX - mobileLookLastX;
        var dy = event.clientY - mobileLookLastY;
        mobileLookLastX = event.clientX;
        mobileLookLastY = event.clientY;

        if (galleryInspectRuntime.active) {
            closeGalleryInspect("mobile-manual-look");
        }

        if (!editMode && typeof clearViewerWASDVisualOffsets === "function") {
            clearViewerWASDVisualOffsets();
            camera.rotation.z = 0;
        }

        camera.rotation.y += dx * mobileLookSensitivityX;
        camera.rotation.x += dy * mobileLookSensitivityY;
        camera.rotation.x = BABYLON.Scalar.Clamp(camera.rotation.x, -0.58, 0.58);
        camera.rotation.z = 0;
        markGalleryViewerActivity("mobile-camera-look");
        return true;
    }

    function handleMobileViewerTap(event) {
        if (!isMobileViewerActive()) {
            return;
        }

        var pickX = scene.pointerX;
        var pickY = scene.pointerY;

        if (
            event &&
            typeof event.clientX === "number" &&
            typeof event.clientY === "number" &&
            canvas &&
            canvas.getBoundingClientRect
        ) {
            var rect = canvas.getBoundingClientRect();
            pickX = event.clientX - rect.left;
            pickY = event.clientY - rect.top;
        }

        var pickResult = scene.pick(pickX, pickY);

        if (!pickResult || !pickResult.hit || !pickResult.pickedMesh) {
            closeGalleryInspect("mobile-empty-tap");
            return;
        }

        var pickedArtworkMesh = getArtworkFromPopupPickMesh(pickResult.pickedMesh);

        if (pickedArtworkMesh) {
            openGalleryInspectTarget(pickedArtworkMesh, { reason: "mobile-artwork-tap" });
            return;
        }

        var pickedModelSlot = getModel3dSlotFromPickedMesh(pickResult.pickedMesh);

        if (artSpheres.includes(pickResult.pickedMesh) || pickedModelSlot) {
            openGalleryInspectTarget(pickedModelSlot || pickResult.pickedMesh, { reason: "mobile-sculpture-tap" });
        }
    }

    function endMobileCanvasLook(event, cancelled) {
        if (!mobileLookActive) {
            resetMobileCanvasMoveGesture();
            return false;
        }

        if (
            event &&
            mobileLookPointerId !== null &&
            event.pointerId !== undefined &&
            event.pointerId !== mobileLookPointerId
        ) {
            return false;
        }

        var wasTap = !cancelled && mobileCanvasGestureMode === "pending" && !mobileLookMoved;
        clearMobileCanvasHoldTimer();

        var releasePointerId = event && event.pointerId !== undefined
            ? event.pointerId
            : mobileLookPointerId;

        if (canvas && canvas.releasePointerCapture && releasePointerId !== null && releasePointerId !== undefined) {
            try {
                canvas.releasePointerCapture(releasePointerId);
            } catch (error) {}
        }

        mobileLookActive = false;
        mobileLookPointerId = null;
        resetMobileCanvasMoveGesture();

        if (wasTap) {
            handleMobileViewerTap(event);
        }

        return true;
    }






    function createGalleryDesktopDpad() {
        var old = document.getElementById("galleryDesktopDpad");
        if (old) old.remove();

        var oldStyle = document.getElementById("galleryDesktopDpadStyle");
        if (oldStyle) oldStyle.remove();

        var style = document.createElement("style");
        style.id = "galleryDesktopDpadStyle";
        style.textContent = `
            #galleryDesktopDpad {
                position: absolute;
                right: clamp(20px, 2.6vw, 36px);
                bottom: calc(env(safe-area-inset-bottom) + 24px);
                z-index: 22;
                display: grid;
                grid-template-columns: repeat(3, 46px);
                grid-template-rows: repeat(2, 46px);
                gap: 6px;
                pointer-events: auto;
                user-select: none;
                -webkit-user-select: none;
                touch-action: none;
                transition: opacity 160ms ease, transform 160ms ease, right 180ms ease, left 180ms ease;
            }
            body.is-editor-authenticated:not(.gallery-edit-mode-active) #galleryDesktopDpad {
                right: calc(var(--gallery-editor-screen-gap, 30px) + 196px);
                left: auto;
            }
            body.gallery-edit-mode-active #galleryDesktopDpad {
                right: auto;
                left: clamp(20px, 2.6vw, 36px);
            }
            #galleryDesktopDpad.is-blocked {
                opacity: 0;
                pointer-events: none;
                transform: translateY(8px);
            }
            .gallery-desktop-dpad-button {
                width: 46px;
                height: 46px;
                display: inline-flex;
                align-items: center;
                justify-content: center;
                border: 1px solid rgba(255,255,255,0.28);
                border-radius: 14px;
                background: rgba(20,20,20,0.46);
                color: rgba(255,255,255,0.94);
                box-shadow: 0 12px 28px rgba(0,0,0,0.24), inset 0 1px 0 rgba(255,255,255,0.12);
                backdrop-filter: blur(14px);
                -webkit-backdrop-filter: blur(14px);
                cursor: pointer;
                padding: 0;
                outline: none;
            }
            .gallery-desktop-dpad-button:hover,
            .gallery-desktop-dpad-button:focus-visible {
                background: rgba(255,255,255,0.16);
                border-color: rgba(255,255,255,0.52);
            }
            .gallery-desktop-dpad-button.is-active {
                transform: translateY(1px) scale(0.97);
                background: rgba(255,255,255,0.28);
            }
            .gallery-desktop-dpad-button svg {
                width: 20px;
                height: 20px;
                fill: none;
                stroke: currentColor;
                stroke-width: 2.4;
                stroke-linecap: round;
                stroke-linejoin: round;
            }
            .gallery-desktop-dpad-button[data-direction="forward"] { grid-column: 2; grid-row: 1; }
            .gallery-desktop-dpad-button[data-direction="turnLeft"] { grid-column: 1; grid-row: 2; }
            .gallery-desktop-dpad-button[data-direction="backward"] { grid-column: 2; grid-row: 2; }
            .gallery-desktop-dpad-button[data-direction="turnRight"] { grid-column: 3; grid-row: 2; }
            @media (max-width: 768px), (pointer: coarse) {
                #galleryDesktopDpad { display: none !important; }
            }
        `;
        document.head.appendChild(style);

        galleryDesktopDpad = document.createElement("div");
        galleryDesktopDpad.id = "galleryDesktopDpad";
        galleryDesktopDpad.setAttribute("aria-label", "On-screen gallery navigation");

        var definitions = [
            { key: "forward", label: "Move forward", path: "M12 19V5M6.5 10.5 12 5l5.5 5.5" },
            { key: "turnLeft", label: "Turn left", path: "M19 12H5m5.5-5.5L5 12l5.5 5.5" },
            { key: "backward", label: "Move backward", path: "M12 5v14m5.5-5.5L12 19l-5.5-5.5" },
            { key: "turnRight", label: "Turn right", path: "M5 12h14m-5.5-5.5L19 12l-5.5 5.5" }
        ];

        definitions.forEach(function (definition) {
            var button = document.createElement("button");
            button.type = "button";
            button.className = "gallery-desktop-dpad-button";
            button.dataset.direction = definition.key;
            button.setAttribute("aria-label", definition.label);
            button.innerHTML = '<svg viewBox="0 0 24 24" aria-hidden="true"><path d="' + definition.path + '"></path></svg>';

            function setPressed(event, pressed) {
                if (!isGalleryDesktopPointerNavigationAvailable()) return;
                if (pressed && typeof isViewerIntroOverlayBlockingMovement === "function" && isViewerIntroOverlayBlockingMovement()) return;
                if (event && event.cancelable) event.preventDefault();
                if (event && event.stopPropagation) event.stopPropagation();

                galleryDesktopDpadState[definition.key] = !!pressed;
                button.classList.toggle("is-active", !!pressed);

                if (pressed && event && event.pointerId !== undefined) {
                    galleryDesktopDpadState.activePointerIds[event.pointerId] = definition.key;
                    try { button.setPointerCapture(event.pointerId); } catch (error) {}
                } else if (event && event.pointerId !== undefined) {
                    delete galleryDesktopDpadState.activePointerIds[event.pointerId];
                }

                if (pressed) {
                    markGalleryViewerActivity("desktop-dpad-" + definition.key);
                }
            }

            button.addEventListener("pointerdown", function (event) { setPressed(event, true); });
            button.addEventListener("pointerup", function (event) { setPressed(event, false); });
            button.addEventListener("pointercancel", function (event) { setPressed(event, false); });
            button.addEventListener("lostpointercapture", function (event) { setPressed(event, false); });
            galleryDesktopDpad.appendChild(button);
        });

        appendGalleryUiElement(galleryDesktopDpad, "controls");
    }

    function syncGalleryDesktopDpadVisibility() {
        if (!galleryDesktopDpad) return;
        var blocked = !isGalleryDesktopPointerNavigationAvailable() ||
            (typeof isViewerIntroOverlayBlockingMovement === "function" && isViewerIntroOverlayBlockingMovement());
        galleryDesktopDpad.classList.toggle("is-blocked", !!blocked);
        if (blocked) resetGalleryDesktopDpadState();
    }

    function configureGalleryFloorIndicatorMesh(mesh, displayType) {
        mesh.isPickable = false;
        mesh.checkCollisions = false;
        mesh.receiveShadows = false;
        mesh.doNotSerialize = true;
        mesh.renderOutline = true;
        mesh.outlineColor = new BABYLON.Color3(0.07, 0.07, 0.07);
        mesh.outlineWidth = 0.035;
        mesh.metadata = {
            displayType: displayType,
            ignoreLocalLightTargeting: true,
            ignoreGalleryStreaming: true
        };
    }

    function getOrCreateGalleryFloorCursorRing() {
        if (galleryFloorCursorRing && !(galleryFloorCursorRing.isDisposed && galleryFloorCursorRing.isDisposed())) {
            return galleryFloorCursorRing;
        }

        galleryFloorCursorRingMaterial = new BABYLON.StandardMaterial("GalleryFloorCursorRingMaterial", scene);
        galleryFloorCursorRingMaterial.diffuseColor = new BABYLON.Color3(1, 1, 1);
        galleryFloorCursorRingMaterial.emissiveColor = new BABYLON.Color3(0.96, 0.96, 0.96);
        galleryFloorCursorRingMaterial.specularColor = BABYLON.Color3.Black();
        galleryFloorCursorRingMaterial.alpha = 0.90;
        galleryFloorCursorRingMaterial.disableLighting = true;
        galleryFloorCursorRingMaterial.backFaceCulling = false;

        galleryFloorCursorRing = BABYLON.MeshBuilder.CreateTorus(
            "GalleryFloorCursorRing",
            { diameter: 0.64, thickness: 0.038, tessellation: 56 },
            scene
        );
        galleryFloorCursorRing.material = galleryFloorCursorRingMaterial;
        configureGalleryFloorIndicatorMesh(galleryFloorCursorRing, "floor-cursor-highlight");
        galleryFloorCursorRing.setEnabled(false);
        return galleryFloorCursorRing;
    }

    function getOrCreateGalleryFloorCursorPulseRing() {
        if (galleryFloorCursorPulseRing && !(galleryFloorCursorPulseRing.isDisposed && galleryFloorCursorPulseRing.isDisposed())) {
            return galleryFloorCursorPulseRing;
        }

        galleryFloorCursorPulseMaterial = new BABYLON.StandardMaterial("GalleryFloorCursorPulseMaterial", scene);
        galleryFloorCursorPulseMaterial.diffuseColor = new BABYLON.Color3(1, 1, 1);
        galleryFloorCursorPulseMaterial.emissiveColor = new BABYLON.Color3(1, 1, 1);
        galleryFloorCursorPulseMaterial.specularColor = BABYLON.Color3.Black();
        galleryFloorCursorPulseMaterial.alpha = 0;
        galleryFloorCursorPulseMaterial.disableLighting = true;
        galleryFloorCursorPulseMaterial.backFaceCulling = false;

        galleryFloorCursorPulseRing = BABYLON.MeshBuilder.CreateTorus(
            "GalleryFloorCursorPulseRing",
            { diameter: 0.64, thickness: 0.032, tessellation: 56 },
            scene
        );
        galleryFloorCursorPulseRing.material = galleryFloorCursorPulseMaterial;
        configureGalleryFloorIndicatorMesh(galleryFloorCursorPulseRing, "floor-cursor-click-pulse");
        galleryFloorCursorPulseRing.outlineWidth = 0.026;
        galleryFloorCursorPulseRing.setEnabled(false);
        return galleryFloorCursorPulseRing;
    }

    function hideGalleryFloorCursorRing() {
        if (galleryFloorCursorRing) galleryFloorCursorRing.setEnabled(false);
    }

    function hideGalleryFloorCursorPulse() {
        galleryFloorCursorPulseStartedAt = 0;
        if (galleryFloorCursorPulseRing) galleryFloorCursorPulseRing.setEnabled(false);
        if (galleryFloorCursorPulseMaterial) galleryFloorCursorPulseMaterial.alpha = 0;
    }

    function pickGalleryFloorFromPointer(event) {
        if (!event || !canvas || !canvas.getBoundingClientRect) {
            return null;
        }

        var rect = canvas.getBoundingClientRect();
        var x = event.clientX - rect.left;
        var y = event.clientY - rect.top;
        var visiblePick = scene.pick(x, y, null, false, camera);

        if (!visiblePick || !visiblePick.hit || !visiblePick.pickedMesh || floorMeshes.indexOf(visiblePick.pickedMesh) === -1) {
            return null;
        }

        return visiblePick;
    }

    function startGalleryFloorCursorClickPulse(event) {
        if (!event || event.button !== 0 || !isGalleryDesktopPointerNavigationAvailable() ||
            (typeof isViewerIntroOverlayBlockingMovement === "function" && isViewerIntroOverlayBlockingMovement()) ||
            desktopViewerMiddleLookActive || isDraggingArtwork || isDraggingSphere) {
            return false;
        }

        var pick = pickGalleryFloorFromPointer(event);
        if (!pick || !pick.hit || !pick.pickedPoint) {
            return false;
        }

        var pulse = getOrCreateGalleryFloorCursorPulseRing();
        pulse.position.copyFrom(pick.pickedPoint);
        pulse.position.y += 0.021;
        pulse.rotationQuaternion = null;
        pulse.rotation.copyFrom(BABYLON.Vector3.Zero());
        pulse.scaling.set(0.82, 0.82, 0.82);
        galleryFloorCursorPulseMaterial.alpha = 0.92;
        galleryFloorCursorPulseStartedAt = typeof performance !== "undefined" && performance.now ? performance.now() : Date.now();
        pulse.setEnabled(true);
        return true;
    }

    function updateGalleryFloorCursorClickPulse() {
        if (!galleryFloorCursorPulseStartedAt || !galleryFloorCursorPulseRing || !galleryFloorCursorPulseMaterial) {
            return;
        }

        var now = typeof performance !== "undefined" && performance.now ? performance.now() : Date.now();
        var t = Math.max(0, Math.min(1, (now - galleryFloorCursorPulseStartedAt) / galleryFloorCursorPulseDurationMs));
        var eased = 1 - Math.pow(1 - t, 3);
        var scale = 0.82 + eased * 0.78;
        galleryFloorCursorPulseRing.scaling.set(scale, scale, scale);
        galleryFloorCursorPulseMaterial.alpha = 0.92 * Math.pow(1 - t, 1.55);

        if (t >= 1) {
            hideGalleryFloorCursorPulse();
        }
    }

    function updateGalleryFloorCursorRingFromPointer(event) {
        galleryFloorCursorFramePending = false;
        event = event || galleryFloorCursorLastEvent;

        if (!event || !isGalleryDesktopPointerNavigationAvailable() ||
            (typeof isViewerIntroOverlayBlockingMovement === "function" && isViewerIntroOverlayBlockingMovement()) ||
            desktopViewerMiddleLookActive || isDraggingArtwork || isDraggingSphere) {
            hideGalleryFloorCursorRing();
            return;
        }

        var pick = pickGalleryFloorFromPointer(event);

        if (!pick || !pick.hit || !pick.pickedPoint) {
            hideGalleryFloorCursorRing();
            return;
        }

        var ring = getOrCreateGalleryFloorCursorRing();
        ring.position.copyFrom(pick.pickedPoint);
        ring.position.y += 0.020;
        ring.rotationQuaternion = null;
        ring.rotation.copyFrom(BABYLON.Vector3.Zero());
        ring.scaling.set(1, 1, 1);
        ring.setEnabled(true);
    }

    function scheduleGalleryFloorCursorRingUpdate(event) {
        galleryFloorCursorLastEvent = event;
        if (galleryFloorCursorFramePending) return;
        galleryFloorCursorFramePending = true;
        requestAnimationFrame(function () {
            updateGalleryFloorCursorRingFromPointer(galleryFloorCursorLastEvent);
        });
    }

    createGalleryDesktopDpad();
    registerGalleryDomEvent("galleryDesktopDpadWindowBlur", window, "blur", function () {
        resetGalleryDesktopDpadState();
        hideGalleryFloorCursorRing();
        hideGalleryFloorCursorPulse();
    });
    registerGalleryDomEvent("galleryDesktopDpadVisibility", document, "visibilitychange", function () {
        if (document.hidden) {
            resetGalleryDesktopDpadState();
            hideGalleryFloorCursorRing();
            hideGalleryFloorCursorPulse();
        }
    });
    registerGalleryDomEvent("galleryDesktopDpadResize", window, "resize", syncGalleryDesktopDpadVisibility);
    registerGalleryDomEvent("galleryFloorCursorPointerMove", canvas, "pointermove", function (event) {
        if (event.pointerType === "mouse" || !event.pointerType) {
            scheduleGalleryFloorCursorRingUpdate(event);
        }
    });
    registerGalleryDomEvent("galleryFloorCursorPointerDown", canvas, "pointerdown", function (event) {
        if (event.pointerType === "mouse" || !event.pointerType) {
            startGalleryFloorCursorClickPulse(event);
        }
    }, true);
    registerGalleryDomEvent("galleryFloorCursorPointerLeave", canvas, "pointerleave", hideGalleryFloorCursorRing);
    syncGalleryDesktopDpadVisibility();

